from flask import Flask, jsonify
from flask_cors import CORS

app = Flask(__name__)
CORS(app)  # Default: Allows all origins, methods, and headers for all routes

# You can also configure CORS for specific origins or routes:
# CORS(app, resources={r"/api/*": {"origins": "http://localhost:3000"}})
# CORS(app, origins=["http://localhost:3000", "http://your-frontend.com"])


@app.route('/')
def hello_world():
    return jsonify(message="Hello from Flask!", data={"name": "Flask App", "version": "1.0"})

@app.route('/api/data')
def get_data():
    return jsonify(data=[
        {"id": 1, "item": "Laptop"},
        {"id": 2, "item": "Mouse"},
        {"id": 3, "item": "Keyboard"}
    ])

if __name__ == '__main__':
    app.run(debug=True)
